#!/usr/bin/env python3
"""Installer — einmalig ausfuehren um update_dashboard.py zu aktualisieren"""
import base64
from pathlib import Path

b64_content = """"""

script_dir = Path(__file__).parent
target = script_dir / "update_dashboard.py"
target.write_bytes(base64.b64decode(b64_content))
lines = len(target.read_text().splitlines())
print(f"Aktualisiert: update_dashboard.py ({lines} Zeilen)")
print("Jetzt ausfuehren: python3 update_dashboard.py")
